// downloading data source files used by the kapow import pipelines.
package fetch

import (
	"archive/zip"
	"bytes"
	"compress/gzip"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

// FetchConfig describes how to retrieve a data source file.
type FetchConfig struct {
	// Name is a short identifier (e.g. "nces") used in archive filenames.
	Name string
	// URL is the HTTP URL to download from.
	URL string
	// Format is the source format before re-compression: "csv", "csv.gz", "gz", "zip".
	Format string
}

// cacheEntry is persisted as a JSON sidecar alongside each archive file.
// It stores the HTTP cache validators from the last successful download so
// that subsequent requests can use conditional GET (ETag / Last-Modified).
type cacheEntry struct {
	ETag         string `json:"etag,omitempty"`
	LastModified string `json:"last_modified,omitempty"`
	File         string `json:"file"` // absolute path to the .xz archive
}

// Fetcher downloads and caches source data files. It stores downloaded files
// as xz-compressed archives in a local cache directory to avoid redundant
// downloads across runs.
type Fetcher struct {
	cacheDir   string
	httpClient *http.Client
}

// New creates a Fetcher that stores cached downloads in the given directory.
func New(cacheDir string) *Fetcher {
	return &Fetcher{
		cacheDir:   cacheDir,
		httpClient: &http.Client{},
	}
}

// CacheDir returns the directory used for cached downloads.
func (f *Fetcher) CacheDir() string {
	return f.cacheDir
}

// Fetch retrieves the data source described by cfg, returning a reader over
// the raw (decompressed) content. The caller is responsible for closing the
// returned reader.
//
// Fetch logic:
//  1. If no sidecar exists, check for manually-dropped archive files and
//     return the newest one without hitting the network.
//  2. Perform a conditional HTTP GET using ETag / Last-Modified from the
//     sidecar when available.
//  3. On 304 Not Modified, return the existing cached archive.
//  4. On network error, fall back to the stale cached archive (if present)
//     with a warning log.
//  5. On 200 OK, decompress the source body, re-compress with xz -9e, save
//     the archive and sidecar, and return the decompressed content.
func (f *Fetcher) Fetch(ctx context.Context, cfg FetchConfig) (io.ReadCloser, error) {
	if err := os.MkdirAll(f.cacheDir, 0o755); err != nil {
		return nil, fmt.Errorf("fetch: create cache dir: %w", err)
	}

	storedExt := storedFormat(cfg.Format)
	sidecarPath := filepath.Join(f.cacheDir, cfg.Name+".cache.json")
	entry, _ := loadSidecar(sidecarPath)

	// 1. When there is no sidecar, check for manually-dropped archive files.
	//    This lets operators place hand-obtained files in the cache directory
	//    for sources that cannot be downloaded automatically.
	if entry == nil {
		if path, ok := f.Latest(cfg.Name, storedExt); ok {
			slog.Info("fetch: using manually-dropped file", "source", cfg.Name, "path", path)
			return openXZ(ctx, path)
		}
	}

	// 2. Build HTTP request, adding conditional headers from the sidecar.
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, cfg.URL, nil)
	if err != nil {
		return nil, fmt.Errorf("fetch: build request: %w", err)
	}
	if entry != nil {
		if entry.ETag != "" {
			req.Header.Set("If-None-Match", entry.ETag)
		}
		if entry.LastModified != "" {
			req.Header.Set("If-Modified-Since", entry.LastModified)
		}
	}

	resp, httpErr := f.httpClient.Do(req)

	// 4. On network error, fall back to stale cache.
	if httpErr != nil {
		if entry != nil && entry.File != "" {
			if _, statErr := os.Stat(entry.File); statErr == nil {
				slog.Warn("fetch: network error, using stale cache",
					"source", cfg.Name, "file", entry.File, "error", httpErr)
				return openXZ(ctx, entry.File)
			}
		}
		return nil, fmt.Errorf("fetch: http get %s: %w", cfg.Name, httpErr)
	}
	defer resp.Body.Close()

	// 3. Handle 304 Not Modified — content unchanged, return existing archive.
	if resp.StatusCode == http.StatusNotModified {
		if entry != nil && entry.File != "" {
			if _, statErr := os.Stat(entry.File); statErr == nil {
				slog.Info("fetch: content unchanged (304), using cached file",
					"source", cfg.Name, "file", entry.File)
				return openXZ(ctx, entry.File)
			}
		}
		return nil, fmt.Errorf("fetch: received 304 but no cached file for %s", cfg.Name)
	}

	// Stale fallback for unexpected non-200 responses.
	if resp.StatusCode != http.StatusOK {
		if entry != nil && entry.File != "" {
			if _, statErr := os.Stat(entry.File); statErr == nil {
				slog.Warn("fetch: non-OK status, using stale cache",
					"source", cfg.Name, "status", resp.StatusCode, "file", entry.File)
				return openXZ(ctx, entry.File)
			}
		}
		return nil, fmt.Errorf("fetch: unexpected status %d for %s", resp.StatusCode, cfg.Name)
	}

	// 5. Download: decompress source body, re-compress with xz, save archive.
	decompressed, err := decompressSource(resp.Body, cfg.Format)
	if err != nil {
		return nil, fmt.Errorf("fetch: decompress source %s: %w", cfg.Name, err)
	}
	defer decompressed.Close()

	// Buffer the decompressed data so we can both archive it and return it.
	data, err := io.ReadAll(decompressed)
	if err != nil {
		return nil, fmt.Errorf("fetch: read body %s: %w", cfg.Name, err)
	}

	archiveFile := filepath.Join(f.cacheDir,
		fmt.Sprintf("%s-%s.%s.xz", cfg.Name, time.Now().UTC().Format("2006-01-02"), storedExt))

	if err := compressXZ(ctx, bytes.NewReader(data), archiveFile); err != nil {
		return nil, fmt.Errorf("fetch: compress archive %s: %w", cfg.Name, err)
	}

	newEntry := &cacheEntry{
		ETag:         resp.Header.Get("ETag"),
		LastModified: resp.Header.Get("Last-Modified"),
		File:         archiveFile,
	}
	if err := saveSidecar(sidecarPath, newEntry); err != nil {
		slog.Warn("fetch: failed to save sidecar", "path", sidecarPath, "error", err)
	}

	slog.Info("fetch: downloaded and archived",
		"source", cfg.Name, "file", archiveFile, "bytes", len(data))

	return io.NopCloser(bytes.NewReader(data)), nil
}

// Latest returns the path to the most recently dated archive file matching
// "{name}-*.{ext}.xz" in the cache directory. Returns ("", false) if none exist.
//
// Files are named with ISO dates (e.g. nces-2026-03-09.csv.xz) so lexicographic
// sort gives the correct newest-first order.
func (f *Fetcher) Latest(name, ext string) (string, bool) {
	pattern := filepath.Join(f.cacheDir, fmt.Sprintf("%s-*.%s.xz", name, ext))
	matches, err := filepath.Glob(pattern)
	if err != nil || len(matches) == 0 {
		return "", false
	}
	sort.Strings(matches)
	return matches[len(matches)-1], true
}

// storedFormat returns the archive extension for a given source format,
// stripping any outer compression layer (e.g. "csv.gz" → "csv").
func storedFormat(format string) string {
	switch strings.ToLower(format) {
	case "csv.gz", "gz":
		return "csv"
	case "zip":
		return "csv"
	default:
		return format
	}
}

// decompressSource wraps r in the appropriate decompressor for the source format.
// The caller is responsible for closing the returned ReadCloser.
func decompressSource(r io.Reader, format string) (io.ReadCloser, error) {
	switch strings.ToLower(format) {
	case "csv.gz", "gz":
		gr, err := gzip.NewReader(r)
		if err != nil {
			return nil, fmt.Errorf("open gzip reader: %w", err)
		}
		return gr, nil

	case "zip":
		// archive/zip requires a ReaderAt; buffer the entire body first.
		data, err := io.ReadAll(r)
		if err != nil {
			return nil, fmt.Errorf("buffer zip body: %w", err)
		}
		zr, err := zip.NewReader(bytes.NewReader(data), int64(len(data)))
		if err != nil {
			return nil, fmt.Errorf("open zip: %w", err)
		}
		if len(zr.File) == 0 {
			return nil, fmt.Errorf("zip archive is empty")
		}
		rc, err := zr.File[0].Open()
		if err != nil {
			return nil, fmt.Errorf("open zip entry: %w", err)
		}
		return rc, nil

	default:
		// Plain format (csv, tsv, …) — pass through unchanged.
		return io.NopCloser(r), nil
	}
}

// compressXZ reads from src and writes an xz-compressed file to dst using the
// system xz binary with -9e (maximum/extreme compression).
func compressXZ(ctx context.Context, src io.Reader, dst string) error {
	f, err := os.Create(dst)
	if err != nil {
		return fmt.Errorf("create xz output: %w", err)
	}
	defer f.Close()

	var stderr bytes.Buffer
	cmd := exec.CommandContext(ctx, "xz", "-9e", "-c") //nolint:gosec
	cmd.Stdin = src
	cmd.Stdout = f
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		_ = os.Remove(dst)
		return fmt.Errorf("xz: %w: %s", err, strings.TrimSpace(stderr.String()))
	}
	return nil
}

// openXZ returns a reader over the decompressed content of an xz archive using
// the system xz binary. The returned reader holds the entire decompressed
// content in memory.
func openXZ(ctx context.Context, path string) (io.ReadCloser, error) {
	var stderr bytes.Buffer
	cmd := exec.CommandContext(ctx, "xz", "-d", "-c", path) //nolint:gosec
	cmd.Stderr = &stderr

	out, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("fetch: xz decompress %s: %w: %s",
			path, err, strings.TrimSpace(stderr.String()))
	}
	return io.NopCloser(bytes.NewReader(out)), nil
}

// loadSidecar reads a cacheEntry from a JSON sidecar file.
// Returns (nil, err) if the file is absent or cannot be parsed.
func loadSidecar(path string) (*cacheEntry, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	var entry cacheEntry
	if err := json.Unmarshal(data, &entry); err != nil {
		return nil, fmt.Errorf("fetch: unmarshal sidecar %s: %w", path, err)
	}
	return &entry, nil
}

// saveSidecar writes a cacheEntry to a JSON sidecar file.
func saveSidecar(path string, entry *cacheEntry) error {
	data, err := json.MarshalIndent(entry, "", "  ")
	if err != nil {
		return fmt.Errorf("fetch: marshal sidecar: %w", err)
	}
	return os.WriteFile(path, data, 0o644) //nolint:gosec
}
