	"path/filepath"
	"strings"
	"testing"

	"github.com/ketang/kapow/tools/kapow/internal/fetch"
)

// skipIfNoXZ skips the test if the system xz binary is not available.
func skipIfNoXZ(t *testing.T) {
	t.Helper()
	if _, err := exec.LookPath("xz"); err != nil {
		t.Skip("xz binary not available in PATH")
	}
}

// makeXZ compresses data using the system xz binary and returns the compressed bytes.
func makeXZ(t *testing.T, data string) []byte {
	t.Helper()
	var buf bytes.Buffer
	cmd := exec.Command("xz", "-c") //nolint:gosec
	cmd.Stdin = strings.NewReader(data)
	cmd.Stdout = &buf
	if err := cmd.Run(); err != nil {
		t.Fatalf("makeXZ: %v", err)
	}
	return buf.Bytes()
}

func TestFetch_Download(t *testing.T) {
	skipIfNoXZ(t)

	want := "col1,col2\nval1,val2\n"
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("ETag", `"abc123"`)
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte(want))
	}))
	defer srv.Close()

	dir := t.TempDir()
	f := fetch.New(dir)
	cfg := fetch.FetchConfig{Name: "test", URL: srv.URL, Format: "csv"}

	rc, err := f.Fetch(context.Background(), cfg)
	if err != nil {
		t.Fatalf("Fetch: %v", err)
	}
	defer rc.Close()

	got, err := io.ReadAll(rc)
	if err != nil {
		t.Fatalf("ReadAll: %v", err)
	}
	if string(got) != want {
		t.Errorf("content: got %q, want %q", got, want)
	}

	// Verify archive was created.
	matches, _ := filepath.Glob(filepath.Join(dir, "test-*.csv.xz"))
	if len(matches) == 0 {
		t.Error("no .xz archive created in cache dir")
	}

	// Verify sidecar was created.
	if _, err := os.Stat(filepath.Join(dir, "test.cache.json")); err != nil {
		t.Error("sidecar JSON not created")
	}
}

func TestFetch_Conditional304(t *testing.T) {
	skipIfNoXZ(t)

	want := "col1,col2\nrow1\n"
	callCount := 0

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		callCount++
		if r.Header.Get("If-None-Match") == `"etag1"` {
			w.WriteHeader(http.StatusNotModified)
			return
		}
		w.Header().Set("ETag", `"etag1"`)
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte(want))
	}))
	defer srv.Close()

	dir := t.TempDir()
	f := fetch.New(dir)
	cfg := fetch.FetchConfig{Name: "cond", URL: srv.URL, Format: "csv"}

	// First fetch — downloads and caches.
	rc1, err := f.Fetch(context.Background(), cfg)
	if err != nil {
		t.Fatalf("first Fetch: %v", err)
	}
	rc1.Close()

	if callCount != 1 {
		t.Errorf("expected 1 HTTP call after first fetch, got %d", callCount)
	}

	// Second fetch — server returns 304; should reuse cached file.
	rc2, err := f.Fetch(context.Background(), cfg)
	if err != nil {
		t.Fatalf("second Fetch: %v", err)
	}
	defer rc2.Close()

	got, _ := io.ReadAll(rc2)
	if string(got) != want {
		t.Errorf("304 content: got %q, want %q", got, want)
	}
	if callCount != 2 {
		t.Errorf("expected 2 HTTP calls total, got %d", callCount)
	}
}

func TestFetch_StaleOnNetworkError(t *testing.T) {
	skipIfNoXZ(t)

	want := "stale,data\n1,2\n"

	// Server that works for the first request.
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte(want))
	}))

	dir := t.TempDir()
	f := fetch.New(dir)
	cfg := fetch.FetchConfig{Name: "stale", URL: srv.URL, Format: "csv"}

	// Prime the cache.
	rc, err := f.Fetch(context.Background(), cfg)
	if err != nil {
		t.Fatalf("prime Fetch: %v", err)
	}
	rc.Close()

	// Shut down the server to simulate network failure.
	srv.Close()

	// Point to an unreachable address; expect stale fallback.
	cfg.URL = "http://127.0.0.1:1/does-not-exist"
	rc2, err := f.Fetch(context.Background(), cfg)
	if err != nil {
		t.Fatalf("stale Fetch: %v", err)
	}
	defer rc2.Close()

	got, _ := io.ReadAll(rc2)
	if string(got) != want {
		t.Errorf("stale content: got %q, want %q", got, want)
	}
}

func TestFetch_ManualDrop(t *testing.T) {
	skipIfNoXZ(t)

	content := "manual,drop\ndata,here\n"
	dir := t.TempDir()

	// Manually place an xz-compressed file in the cache directory.
	xzPath := filepath.Join(dir, "manual-2026-01-01.csv.xz")
	if err := os.WriteFile(xzPath, makeXZ(t, content), 0o644); err != nil {
		t.Fatalf("write manual xz: %v", err)
	}

	// Fetcher should use the manually-dropped file without hitting the network.
	called := false
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		called = true
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte("should not be reached"))
	}))
	defer srv.Close()

	f := fetch.New(dir)
	cfg := fetch.FetchConfig{Name: "manual", URL: srv.URL, Format: "csv"}

	rc, err := f.Fetch(context.Background(), cfg)
	if err != nil {
		t.Fatalf("Fetch: %v", err)
	}
	defer rc.Close()

	if called {
		t.Error("HTTP server was called despite manual-drop file being present")
	}

	got, _ := io.ReadAll(rc)
	if string(got) != content {
		t.Errorf("manual drop content: got %q, want %q", got, content)
	}
}

func TestFetch_GzipSource(t *testing.T) {
	skipIfNoXZ(t)

	want := "col1,col2\ngzip,data\n"

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var buf bytes.Buffer
		gw := gzip.NewWriter(&buf)
		_, _ = gw.Write([]byte(want))
		gw.Close()
		w.Header().Set("Content-Type", "application/gzip")
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write(buf.Bytes())
	}))
	defer srv.Close()

	dir := t.TempDir()
	f := fetch.New(dir)
	cfg := fetch.FetchConfig{Name: "gzipped", URL: srv.URL, Format: "csv.gz"}

	rc, err := f.Fetch(context.Background(), cfg)
	if err != nil {
		t.Fatalf("Fetch: %v", err)
	}
	defer rc.Close()

	got, _ := io.ReadAll(rc)
	if string(got) != want {
		t.Errorf("gzip content: got %q, want %q", got, want)
	}

	// Should be archived as .csv.xz (gzip wrapper stripped).
	matches, _ := filepath.Glob(filepath.Join(dir, "gzipped-*.csv.xz"))
	if len(matches) == 0 {
		t.Error("expected gzipped-*.csv.xz archive, none found")
	}
}

func TestFetch_ZipSource(t *testing.T) {
	skipIfNoXZ(t)

	want := "col1,col2\nzip,data\n"

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var buf bytes.Buffer
		zw := zip.NewWriter(&buf)
		entry, _ := zw.Create("data.csv")
		_, _ = entry.Write([]byte(want))
		zw.Close()
		w.Header().Set("Content-Type", "application/zip")
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write(buf.Bytes())
	}))
	defer srv.Close()

	dir := t.TempDir()
	f := fetch.New(dir)
	cfg := fetch.FetchConfig{Name: "zipped", URL: srv.URL, Format: "zip"}

	rc, err := f.Fetch(context.Background(), cfg)
	if err != nil {
		t.Fatalf("Fetch: %v", err)
	}
	defer rc.Close()

	got, _ := io.ReadAll(rc)
	if string(got) != want {
		t.Errorf("zip content: got %q, want %q", got, want)
	}

	// Should be archived as .csv.xz (zip wrapper stripped).
	matches, _ := filepath.Glob(filepath.Join(dir, "zipped-*.csv.xz"))
	if len(matches) == 0 {
		t.Error("expected zipped-*.csv.xz archive, none found")
	}
}

func TestLatest_ReturnsNewest(t *testing.T) {
	dir := t.TempDir()

	// Create several fake archive files with different dates.
	for _, name := range []string{
		"nces-2025-01-01.csv.xz",
		"nces-2025-12-31.csv.xz",
		"nces-2026-03-01.csv.xz",
	} {
		if err := os.WriteFile(filepath.Join(dir, name), []byte("x"), 0o644); err != nil {
			t.Fatalf("write %s: %v", name, err)
		}
	}

	f := fetch.New(dir)
	got, ok := f.Latest("nces", "csv")
	if !ok {
		t.Fatal("Latest returned false, expected a match")
	}
	want := filepath.Join(dir, "nces-2026-03-01.csv.xz")
	if got != want {
		t.Errorf("Latest got %q, want %q", got, want)
	}
}

func TestLatest_EmptyDir(t *testing.T) {
	dir := t.TempDir()
	f := fetch.New(dir)
	_, ok := f.Latest("nofile", "csv")
	if ok {
		t.Error("Latest should return false when no matching files exist")
	}
}

func TestLatest_IgnoresOtherSources(t *testing.T) {
	dir := t.TempDir()

	// Place files for two different sources.
	for _, name := range []string{
		"ipeds-2026-01-01.csv.xz",
		"nces-2025-06-01.csv.xz",
	} {
		if err := os.WriteFile(filepath.Join(dir, name), []byte("x"), 0o644); err != nil {
			t.Fatalf("write %s: %v", name, err)
		}
	}

	f := fetch.New(dir)
	got, ok := f.Latest("nces", "csv")
	if !ok {
		t.Fatal("Latest returned false for nces")
	}
	if !strings.Contains(got, "nces-") {
		t.Errorf("Latest returned non-nces file: %q", got)
	}
}
